    if (multiplesOfP.length === 1) {
        // Only one element divisible by p. If it is p, we returned true. If it is > p, the GCD must be >= p, but since it's the only one, it is > p.
        return false; 
    }

    // If multiplesOfP.length >= 2, we check if the GCD of *all* elements in multiplesOfP is exactly p.
    // Let G = GCD(multiplesOfP). If G = p, then the subsequence formed by all elements in multiplesOfP is a candidate.
