/**
 * Solves the problem by processing updates and checking for the existence of a good subsequence after each query.
 * @param {number[]} nums The initial integer array.
 * @param {number} p The target GCD.
 * @param {number[][]} queries The list of update queries.
 * @returns {number} The count of queries after which a good subsequence exists.
 */
function solve(nums, p, queries) {
    let currentNums = [...nums];
    let goodSubsequenceCount = 0;
    const n = nums.length;

    for (const query of queries) {
        const [index, newValue] = query;

        // 1. Perform the update
        currentNums[index] = newValue;

        // 2. Check for the existence of a good subsequence
        const exists = checkGoodSubsequence(currentNums, p);

        // 3. Update the count
